"use client"

import Image from "next/image"
import { useState } from "react"
import { Product } from "../types"
import { ProdactCard } from "../components/ProdactCard"


const productList = [
    { id: "1", title: "худі", price: 700, image: "/images/hoodie.jpg" },
    { id: "2", title: "ручка", price: 350, image: "/images/handle.jpg" },
    { id: "3", title: "горнятко", price: 120, image: "/images/cup.jpg" },
    { id: "4", title: "кофта", price: 400, image: "/images/blouse.jpg" },
    { id: "5", title: "зошит", price: 250, image: "/images/notebook.jpg" },
    { id: "6", title: "футболка", price: 150, image: "/images/t-shirt.jpg" },

]

export default function Home() {
    const [currentProduct, setCurrentProduct] = useState(0)

    const handlePrev = () => {
        setCurrentProduct(prev => Math.max(0, prev - 1))
    }

    const handleNext = () => {
        setCurrentProduct(prev => Math.min(productList.length - 1, prev + 1))
    }
    return (

        <div>

            <header>
                <Image src="/images/logo.jpg" alt="Logo" width={100} height={100}></Image>
                <h1>ТОВАР CREATOR IT ACADEMY</h1>

                <button><Image src="/images/basket.jpg" alt="Basket" width={30} height={30}></Image></button>
            </header>


            <main>

                <button onClick={handlePrev}>Попередній</button>
                <Product data={productList[currentProduct]}></Product>
                <button onClick={handleNext}>Наступний</button>

            </main>
            <footer>


            </footer>

        </div>


    )
}